        "onboarding_fertig_startcoins": ["de": "50 Start-Coins erhalten", "en": "Received 50 start coins", "es": "Recibidas 50 monedas de inicio", "fr": "Reçu 50 pièces de départ", "it": "Received 50 start coins", "pt": "Recebeste 50 moedas iniciais"],
