        "onboarding_tutorial_3_titel": ["de": "Kaufe im Shop", "en": "Buy in the Shop", "es": "Compra en la tienda", "fr": "Achète dans la boutique", "it": "Buy in the Shop", "pt": "Compra na loja"],
        "onboarding_tutorial_4_text": ["de": "Dekorationen geben dir kurzfristige Boni, aber nutze sie weise!", "en": "Decorations give you short-term bonuses, but use them wisely!", "es": "Las decoraciones te dan bonos a corto plazo, ¡pero úsalas con sabiduría!", "fr": "Les décorations te donnent des bonus à court terme, mais utilise-les avec sagesse !", "it": "Le decorazioni ti danno bonus a breve termine, ma usale con saggezza!", "pt": "As decorações dão-te bónus a curto prazo, mas usa-as com sabedoria!"],
        "onboarding_tutorial_4_titel": ["de": "Deko & Belohnung", "en": "Decorations & Rewards", "es": "Decoraciones y recompensas", "fr": "Décorations et récompenses", "it": "Decorazioni e ricompense", "pt": "Decorações e recompensas"],
        "onboarding_tutorial_5_text": ["de": "Gegenstände lassen Unkraut wachsen, das XP und Fortschritt blockiert.", "en": "Items can cause weeds to grow, hindering XP and progress.", "es": "Los objetos pueden hacer que crezcann malas hierbas, lo que dificulta la XP.", "fr": "Les objets peuvent faire de l'herbe pousse, ce qui freine l'XP.", "it": "Oggetti possono far crescere le erbacce, ostacolando l'XP.", "pt": "Os itens podem causar ervas daninhas, dificultando o XP."],
        "onboarding_tutorial_5_titel": ["de": "Achtung vor Unkraut!", "en": "Beware of Weeds!", "es": "¡Cuidado mit Unkraut!", "fr": "Attention aux mauvaises herbes !", "it": "Attenzione alle erbacce!", "pt": "Cuidado com as ervas daninhas!"],
        "onboarding_tutorial_blase": ["de": "So funktioniert dein Garten!", "en": "This is how your garden works!", "es": "¡Así funciona tu jardín!", "fr": "Voici comment fonctionne ton jardin !", "it": "Ecco come funktioniert il tuo giardino!", "pt": "É assim que o teu jardim funciona!"],
        "onboarding_tutorial_giessen_blase": ["de": "Zieh den Wassertropfen auf die Pflanze, um sie zu gießen!", "en": "Drag the water drop onto the plant to water it!", "es": "¡Arrastra la gota de agua a la planta para regarla!", "fr": "Fais glisser la goutte d'eau sur la plante pour l'arroser !", "it": "Drag the water drop onto the plant to water it!", "pt": "Arrasta a gota de água para a planta para a regares!"],
        "onboarding_tutorial_giessen_erfolg": ["de": "Klasse! So pflegst du deine Gewohnheiten.", "en": "Great! This is how you nurture your habits.", "es": "¡Genial! Así es como cuidas tus hábitos.", "fr": "Génial ! C'est ainsi que tu cultives tes habitudes.", "it": "Great! This is how you nurture your habits.", "pt": "Espetacular! É assim que nutres os teus hábitos."],
        "onboarding_tutorial_giessen_test": ["de": "Deine erste Pflanze", "en": "Your first plant", "es": "Tu primera planta", "fr": "Ta première plante", "it": "Your first plant", "pt": "A tua primeira planta"],
        "onboarding_tutorial_interactive_shop_bubble": ["de": "Im Shop kannst du deine Coins gegen tolle Gegenstände eintauschen!", "en": "In the shop, you can exchange your coins for great items!", "es": "¡En la tienda puedes canjear tus monedas por objetos geniales!", "fr": "Dans la boutique, tu peux échanger tes pièces contre de superbes objets !", "it": "In the shop, you can exchange your coins for great items!", "pt": "Na loja, podes trocar as tuas moedas por itens incríveis!"],
        "onboarding_tutorial_interactive_shop_buy": ["de": "Kauf dir mal diesen Dünger!", "en": "Go ahead and buy this fertilizer!", "es": "¡Cómprate este fertilizante!", "fr": "Achète cet engrais !", "it": "Go ahead and buy this fertilizer!", "pt": "Compra este fertilizante!"],
        "onboarding_tutorial_interactive_shop_success": ["de": "Stark! Items geben dir sofortige Vorteile im Garten.", "en": "Awesome! Items give you immediate benefits in the garden.", "es": "¡Genial! Los objetos te dan beneficios inmediatos en el jardín.", "fr": "Génial ! Les objets te procurent des avantages immédiats dans le jardin.", "it": "Awesome! Items give you immediate benefits in the garden.", "pt": "Incrível! Os itens dão-te benefícios imediatos no jardim."],
        "onboarding_tutorial_powerup_bubble": ["de": "Ich gebe dir verschiedene Effekte für den Garten. Benutze sie um schöne Fortschritte zu erreichen.", "en": "I'll give you various effects for the garden. Use them to make beautiful progress.", "es": "Te daré varios efectos para el jardín. Úsalos para lograr un progreso hermoso.", "fr": "Je vais te donner divers effets pour le jardin. Utilise-les pour faire de beaux progrès.", "it": "Ti darò vari effetti per il giardino. Usali per fare bei progressi.", "pt": "Vou dar-te vários efeitos para o jardim. Usa-os para fazeres belos progressos."],
        "onboarding_tutorial_powerup_detail_hint": ["de": "Tippe auf den Schlüssel, um ihn einzusetzen!", "en": "Tap the key to use it!", "es": "¡Toca la llave para usarla!", "fr": "Appuie sur la clé pour l'utiliser !", "it": "Tocca la chiave per usarla!", "pt": "Tocca na chave para a usares!"],
        "onboarding_tutorial_powerup_active_success": ["de": "Stark! Der Goldene Schlüssel ist nun aktiv. Du erhältst jetzt 1.5x mehr XP!", "en": "Awesome! The Golden Key is now active. You now get 1.5x more XP!", "es": "¡Genial! La Llave Dorada está activa. ¡Ahora obtienes 1.5x más XP!", "fr": "Super ! La Clé Dorée est maintenant active. Tu reçois maintenant 1.5x plus d'XP !", "it": "Ottimo! La Chiave Dorata è ora attiva. Ricevi ora 1.5x più XP!", "pt": "Incrível! A Chave Dourada está agora ativa. Recebes agora 1.5x mais XP!"],
        "onboarding_tutorial_interactive_weed_bubble": ["de": "Unkraut macht deinen Garten schwächer und du verdienst weniger XP! Vermeide es, indem du nicht zu viele Dekorationen kaufst.", "en": "Weeds make your garden weaker and you earn less XP! Avoid them by not buying too many decorations.", "es": "¡Las malas hierbas debilitan tu jardín y ganas menos XP! Evítalas no comprando demasiadas decoraciones.", "fr": "Les mauvaises herbes affaiblissent ton jardin et tu gagnes moins d'XP ! Évite-les en n'achetant pas trop de décorations.", "it": "Le erbacce indeboliscono il tuo giardino e guadagni meno XP! Evitale non comprando troppe decorazioni.", "pt": "As ervas daninhas enfraquecem o teu jardim e ganhas menos XP! Evita-as não comprando demasiadas decorações."],
        "onboarding_tutorial_interactive_weed_warning": ["de": "Dekorationen locken langfristig Unkraut an. Je mehr Deko, desto höher die Gefahr im Glücksrad!", "en": "Decorations attract weeds in the long run. The more deco, the higher the danger in the wheel!", "es": "Las decoraciones atraen malas hierbas a largo plazo. ¡A más decoración, mayor peligro en la ruleta!", "fr": "Les décorations attirent les mauvaises herbes à long terme. Plus il y a de déco, plus le danger est grand dans la roue !", "it": "Le decorazioni attraggono le erbacce a lungo termine. Più decorazioni ci sono, maggiore è il pericolo nella ruota!", "pt": "As decorações atraem ervas daninhas a longo prazo. Quanto mais decoração, maior o perigo na roleta!"],
        "onboarding_tutorial_interactive_xp_bubble": ["de": "Tippe auf die Pflanze oben, um sie zu gießen und XP zu sammeln!", "en": "Tap the plant above to water it and collect XP!", "es": "¡Toca la planta arriba para regarla y ganar XP!", "fr": "Appuie sur la plante ci-dessus pour l'arroser et gagner de l'XP !", "it": "Tap the plant above to water it and collect XP!", "pt": "Toca na planta acima para a regares e ganhares XP!"],
        "onboarding_tutorial_interactive_xp_success": ["de": "Super! Wenn der Ring voll ist, steigt deine Pflanze ein Level auf.", "en": "Great! When the ring is full, your plant levels up.", "es": "¡Genial! Quando el círculo esté lleno, tu planta subirá de nivel.", "fr": "Super ! Quand l'anneau est plein, ta plante monte de niveau.", "it": "Great! When the ring is full, your plant levels up.", "pt": "Espetacular! Quando o anel estiver cheio, a tua planta sobe de nível."],
        "onboarding_tutorial_xp_goal": ["de": "DEIN ZIEL", "en": "YOUR GOAL", "es": "TU OBJETIVO", "fr": "TON OBJECTIF", "it": "IL TUO OBIETTIVO", "pt": "O TEU OBJETIVO"],
        "onboarding_tutorial_xp_success_final": ["de": "You go!", "en": "You go!", "es": "¡Tú puedes!", "fr": "C'est parti !", "it": "You go!", "pt": "Tu consegues!"],
        "onboarding_tutorial_weed_decoration_hint": ["de": "Kauf dir eine Deko für schnelle Boni!", "en": "Buy a decoration for quick bonuses!", "es": "¡Compra una decoración para obtener bonos rápidos!", "fr": "Achète une décoration pour des bonus rapides !", "it": "Compra una decorazione per dei bonus rapidi!", "pt": "Compra uma decoração para bónus rápidos!"],
        "onboarding_weiter": ["de": "WEITER", "en": "CONTINUE", "es": "CONTINUAR", "fr": "CONTINUER", "it": "CONTINUA", "pt": "CONTINUAR"],
        "onboarding_willkommen_blase": ["de": "Hallo! Ich bin dein Garten-Guide. Lass uns zusammen deinen persönlichen Garten anlegen!", "en": "Hello! I'm your garden guide. Let's create your personal garden together!", "es": "¡Hola! Soy tu guía del jardín. ¡Curemos juntos tu jardín personal!", "fr": "Bonjour ! Je suis ton guide du jardin. Créons ton jardin personnel ensemble !", "it": "Hello! I'm your garden guide. Let's create your personal garden together!", "pt": "Olá! Sou o teu guia do jardim. Vamos criar o teu jardim pessoal juntos!"],
        "onboarding_willkommen_titel": ["de": "Willkommen im Garten", "en": "Welcome to the Garden", "es": "Bienvenido al Jardín", "fr": "Bienvenue dans le jardin", "it": "Welcome to the Garden", "pt": "Bem-vindo ao Jardim"],
        "onboarding_willkommen_untertitel": ["de": "Baue Gewohnheiten auf, die wachsen.", "en": "Build habits that grow.", "es": "Crea hábitos que crezcan.", "fr": "Crée des habitudes qui grandissent.", "it": "Build habits that grow.", "pt": "Cria hábitos que cresçam."],
        "onboarding_xp_blase": ["de": "Mit jedem Gießen sammelst du XP. Deine Pflanzen wachsen von Bronze bis Diamant!", "en": "With every watering, you collect XP. Your plants grow from Bronze to Diamond!", "es": "Con cada riego, coleccionas XP. ¡Tus plantas crecen de bronce a diamante!", "fr": "À chaque arrosage, tu collectes de l'XP. Tes plantes poussent de Bronze à Diamant !", "it": "With every watering, you collect XP. Your plants grow from Bronze to Diamond!", "pt": "Com cada rega, recolhes XP. As tuas plantas crescem de Bronze a Diamante!"],
        "onboarding_zeit_blase": ["de": "Wann möchtest du deine Gewohnheiten erledigen?", "en": "When do you want to do your habits?", "es": "¿Cuándo quieres realizar tus hábitos?", "fr": "Quand veux-tu accomplir tes habitudes ?", "it": "When do you want to do your habits?", "pt": "Quando queres realizar os teus hábitos?"],
        "onboarding_zeit_blase_personal": ["de": "Wann möchtest du an %@ erinnert werden?", "en": "When do you want to be reminded of %@?", "es": "¿Cuándo quieres que se te recuerde %@?", "fr": "Quand veux-tu qu'on te rappelle %@ ?", "it": "When do you want to be reminded of %@?", "pt": "Quando queres ser lembrado de %@?"],
        "onboarding_zeit_progress": ["de": "Schritt %d von %d", "en": "Step %d of %d", "es": "Paso %d de %d", "fr": "Étape %d sur %d", "it": "Step %d of %d", "pt": "Passo %d de %d"],
        "onboarding_zeit_erklaerung": ["de": "Du bekommst täglich eine Erinnerung zu dieser Zeit.", "en": "You will receive a daily reminder at this time.", "es": "Recibirás un recordatorio diario a esta hora.", "fr": "Tu recevras un rappel quotidien à cette heure.", "it": "You will receive a daily reminder at this time.", "pt": "Receberás um lembrete diário a esta hora."],
        "onboarding_zeit_erklaerung_personal": ["de": "Du bekommst täglich eine Erinnerung für diese Pflanze.", "en": "You will receive a daily reminder for this plant.", "es": "Recibirás un recordatorio diario para esta planta.", "fr": "Tu recevras un rappel quotidien pour cette plante.", "it": "You will receive a daily reminder for this plant.", "pt": "Receberás um lembrete diário para esta planta."],
