        "plant.aloe_vera.symbolism": ["de": "Heilt und regeneriert still im Hintergrund – weniger Handy", "en": "Heals and regenerates silently – less phone time", "es": "Cura y regenera en silencio – menos tiempo de pantalla", "fr": "Guérit et régénère silencieusement – moins de téléphone", "it": "Heals and regenerates silently – less phone time", "pt": "Cura e regenera silenciosamente – menos telemóvel"],
